package viewregistry

import (
	"github.com/ethereum/go-ethereum/accounts/abi"
	"github.com/ethereum/go-ethereum/common"
)

// ViewBytecode is the compiled bytecode for View.sol.
// Compiled with: solc --bin --optimize --optimize-runs 200 --evm-version paris view/View.sol
var ViewBytecode = common.FromHex("")

// ViewConstructorArgs encodes: constructor(string name, address creator, address pricing)
var ViewConstructorArgs = abi.Arguments{
	{Type: mustType("string")},
	{Type: mustType("address")},
	{Type: mustType("address")},
}

func mustType(t string) abi.Type {
	typ, err := abi.NewType(t, "", nil)
	if err != nil {
		panic(err)
	}
	return typ
}
